// Constants - Edit these values to customize the trend
const DAYS_AGO_SEARCH_BROKE = 21;
const LIKELIHOOD_ZERO_RESULTS = 50;
const LIKELIHOOD_CHURN_AFTER_SEARCH = 18;

if (type === "event") {
    const NOW = dayjs();
    const TIME_WHEN_SEARCH_GOT_BAD = NOW.subtract(DAYS_AGO_SEARCH_BROKE, 'days');
    const EVENT_TIME = dayjs(record.time);

    // After search quality degraded
    if (EVENT_TIME.isAfter(TIME_WHEN_SEARCH_GOT_BAD)) {
        // Search returns no results more often
        if (record.event === "search") {
            if (chance.bool({ likelihood: LIKELIHOOD_ZERO_RESULTS })) {
                record["results count"] = 0;
            }
        }

        // Users churn (remove event)
        if (chance.bool({ likelihood: LIKELIHOOD_CHURN_AFTER_SEARCH })) {
            return {};
        }
    }
}
return record;

// Constants - Edit these to customize experiment effects
const DAYS_AGO_EXPERIMENT_LAUNCHED = 14;
const VARIANT_A_WATCH_TIME_BOOST = 1.7; // 70% increase
const VARIANT_A_SUBSCRIBE_LIKELIHOOD = 75;
const VARIANT_B_WATCH_TIME_REDUCTION = 0.5; // 50% decrease
const VARIANT_B_UNSUBSCRIBE_LIKELIHOOD = 75;

if (type === "everything") {
    const NOW = dayjs();
    const TIME_WE_EXPERIMENTED = NOW.subtract(DAYS_AGO_EXPERIMENT_LAUNCHED, 'days');

    // Find which variant the user was in
    const hadVariantA = record.some(event =>
        event.event === "$experiment_started" &&
        event["Variant name"] === "A"
    );

    const hadVariantB = record.some(event =>
        event.event === "$experiment_started" &&
        event["Variant name"] === "B"
    );

    // Modify events based on variant
    record.forEach((event, idx) => {
        const EVENT_TIME = dayjs(event.time);

        // Only apply changes after experiment launch
        if (EVENT_TIME.isAfter(TIME_WE_EXPERIMENTED)) {
            if (hadVariantA) {
                // Variant A: Better outcomes
                if (event.event === "watch video" && chance.bool({ likelihood: VARIANT_A_SUBSCRIBE_LIKELIHOOD })) {
                    // Increase watch time
                    event["watch time"] = v.round(event["watch time"] * VARIANT_A_WATCH_TIME_BOOST);

                    // Add subscribe event after watching
                    const subscribeEvent = {
                        event: "subscribe",
                        time: dayjs(event.time).add(1, 'minute').toISOString(),
                        user_id: event.user_id
                    };
                    record.splice(idx + 1, 0, subscribeEvent);
                }
            } else if (hadVariantB) {
                // Variant B: Worse outcomes
                if (event.event === "subscribe" && chance.bool({ likelihood: VARIANT_B_UNSUBSCRIBE_LIKELIHOOD })) {
                    // Remove subscribe events
                    record.splice(idx, 1);
                }

                if (event.event === "watch video") {
                    // Decrease watch time
                    event["watch time"] = v.round(event["watch time"] * VARIANT_B_WATCH_TIME_REDUCTION);
                }
            }
        }
    });
}
return record;

// Constants - Edit these to customize the trend
const DAYS_AGO_IMPROVEMENT = 15;
const REVENUE_BOOST_AFTER = 1.5; // 50% increase
const WATCH_TIME_BOOST_AFTER = 1.5; // 50% increase
const VOLUME_DROP_BEFORE = 33; // % of events to drop

if (type === "event") {
    const NOW = dayjs();
    const IMPROVEMENT_DATE = NOW.subtract(DAYS_AGO_IMPROVEMENT, 'day');
    const EVENT_TIME = dayjs(record.time);

    // After improvement: Better metrics
    if (EVENT_TIME.isAfter(IMPROVEMENT_DATE)) {
        if (record.event === "checkout") {
            record.amount = Math.round(record.amount * REVENUE_BOOST_AFTER);
        }
        if (record.event === "watch video") {
            record.watchTimeSec = Math.round(record.watchTimeSec * WATCH_TIME_BOOST_AFTER);
        }
    }

    // Before improvement: Lower volume
    if (EVENT_TIME.isBefore(IMPROVEMENT_DATE)) {
        if (chance.bool({ likelihood: VOLUME_DROP_BEFORE })) {
            return {}; // Remove event
        }
    }
}
return record;

// Constants - Edit these to customize user segmentation
const PREMIUM_THEME_VALUE = "custom";
const PREMIUM_CHECKOUT_MULTIPLIER = 3;
const TIME_VARIANCE_HOURS = 48;

if (type === "everything") {
    // Count events by theme
    const numCustomMode = record.filter(a => a.theme === PREMIUM_THEME_VALUE).length;
    const numLightMode = record.filter(a => a.theme === 'light').length;
    const numDarkMode = record.filter(a => a.theme === 'dark').length;

    // Premium theme users get more checkout events
    if (numCustomMode > numLightMode || numCustomMode > numDarkMode) {
        const checkoutEvents = record.filter(a => a.event === 'checkout');

        // Create additional checkouts
        const newCheckouts = checkoutEvents.map(a => {
            const randomInt = u.integer(-TIME_VARIANCE_HOURS, TIME_VARIANCE_HOURS);
            return {
                ...a,
                time: dayjs(a.time).add(randomInt, 'hour').toISOString(),
                event: "checkout",
                amount: a.amount * 2,
                coupon: "50%OFF"
            };
        });

        // Add new checkout events
        record.push(...newCheckouts);
    }
}
return record;

// Constants - Edit these to customize churn behavior
const LOW_QUALITY_FORMATS = ["480p", "360p", "240p"];
const CHURN_LIKELIHOOD = 50;

if (type === "everything") {
    // Count video quality
    const lowQualityWatches = record.filter(a =>
        a.event === 'watch video' &&
        LOW_QUALITY_FORMATS.includes(a.quality)
    );

    const highQualityWatches = record.filter(a =>
        a.event === 'watch video' &&
        !LOW_QUALITY_FORMATS.includes(a.quality)
    );

    // Users who watch more low quality content churn
    if (lowQualityWatches.length > highQualityWatches.length) {
        if (chance.bool({ likelihood: CHURN_LIKELIHOOD })) {
            // Remove second half of events (churn)
            const midpoint = Math.floor(record.length / 2);
            record = record.slice(0, midpoint);
        }
    }
}
return record;

// Constants - Edit these to customize the outage
const OUTAGE_START = "2025-10-19";
const OUTAGE_END = "2025-10-22";
