// Constants - Edit these to customize campaign effect
const EMAIL_UTM_MEDIUM = "email (marketing)";
const BOOST_PER_EMAIL = 0.10; // 10% per email
const MAX_BOOST = 0.50; // Max 50% boost
const PROPERTY_TO_BOOST = "amount_usd";

if (type === "everything") {
    // Count email reads
    const emailReads = record.filter(e => {
        if (e.hasOwnProperty('utm_medium')) {
            if (e.utm_medium === EMAIL_UTM_MEDIUM) {
                return true;
            }
        }
        return false;
    });

    const numEmailReads = emailReads.length;

    // Apply cumulative boost based on email engagement
    if (numEmailReads > 0) {
        record.forEach(e => {
            if (e.hasOwnProperty(PROPERTY_TO_BOOST)) {
                // Calculate boost, capped at max
                const boostFactor = 1 + Math.min(numEmailReads * BOOST_PER_EMAIL, MAX_BOOST);
                e[PROPERTY_TO_BOOST] = Math.round(e[PROPERTY_TO_BOOST] * boostFactor);
            }
        });
    }
}
return record;

// Constants - Edit these to customize approval rates
const DAYS_AGO_RATE_CHANGE = 17;
const BEFORE_DECLINE_RATE = 60;
const AFTER_CONVERSION_RATE = 60;
const AFTER_APPROVAL_RATE = 60;
const MIN_DELAY_MINUTES = 1;
const MAX_DELAY_MINUTES = 20;

if (type === "funnel-post") {
    const RATE_CHANGE_DATE = dayjs().subtract(DAYS_AGO_RATE_CHANGE, 'd');

    // Check if this is a loan application funnel
    if (record[0]?.event === "loan app start") {
        const funnelStartTime = dayjs(record[0].time);

        // Before rate change: Student loans declined
        if (funnelStartTime.isBefore(RATE_CHANGE_DATE)) {
            if (record[0]["loan type"] === "student loan") {
                if (chance.bool({ likelihood: BEFORE_DECLINE_RATE })) {
                    record.forEach((r) => {
                        r["application status"] = "declined";
                    });
                }
            }
        }

        // After rate change: Better outcomes
        if (funnelStartTime.isAfter(RATE_CHANGE_DATE)) {
            // Convert student loans to auto loans
            if (record[0]["loan type"] === "student loan") {
                if (chance.bool({ likelihood: AFTER_CONVERSION_RATE })) {
                    record.forEach((r) => {
                        r["loan type"] = "auto loan";
                    });
                }
            }

            // Auto loans get approved
            if (record[0]["loan type"] === "auto loan") {
                if (chance.bool({ likelihood: AFTER_APPROVAL_RATE })) {
                    record.forEach((r) => {
                        r["application status"] = "approved";
                    });
                }

                // But they take longer
                record.forEach((ev, index) => {
                    if (index > 0) {
                        const minutes = u.integer(MIN_DELAY_MINUTES, MAX_DELAY_MINUTES);
                        ev.time = dayjs(ev.time).add(minutes, "minute").toISOString();
                    }
                });
            }
        }
    }
}
return record;

// Constants - Edit these to customize AI impact
const HIGH_PERFORMING_MODEL = "Q";
const LOW_PERFORMING_MODEL = "BERT";
const PRODUCT_THRESHOLD = 3;
const HIGH_PRODUCT_EVENT_BOOST_LIKELIHOOD = 40;
const LOW_PRODUCT_EVENT_REDUCTION_LIKELIHOOD = 40;
const EVENT_DUPLICATION_RATE = 20;
const EVENT_DELETION_RATE = 20;
const MIN_EVENT_DELAY_MINUTES = 1;
const MAX_EVENT_DELAY_MINUTES = 90;

if (type === "everything") {
    // Count AI model exposures
    const AIModelExposure = record.map(a => a["AI model"]).filter(Boolean);
    const numHighPerformingExposure = AIModelExposure.filter(a => a === HIGH_PERFORMING_MODEL).length;
    const numLowPerformingExposure = AIModelExposure.filter(a => a === LOW_PERFORMING_MODEL).length;

    // AI exposure affects product count
    if (chance.bool({ likelihood: 50 })) {
        const ratio = Math.floor(numHighPerformingExposure / numLowPerformingExposure) || 1;
        // Note: This assumes a listOfProducts() function exists in meta.defaults
        // Adjust based on actual schema
    }

    const { profile } = meta;

    // High product users: More events and retention
    if (profile["products used"] && profile["products used"].length > PRODUCT_THRESHOLD) {
        if (chance.bool({ likelihood: HIGH_PRODUCT_EVENT_BOOST_LIKELIHOOD })) {
            // Duplicate events randomly
            record.forEach((ev, index) => {
                if (index > 0) {
                    if (chance.bool({ likelihood: EVENT_DUPLICATION_RATE })) {
                        const clone = u.clone(ev);
                        const delay = u.integer(MIN_EVENT_DELAY_MINUTES, MAX_EVENT_DELAY_MINUTES);
                        clone.time = dayjs(ev.time).add(delay, "minute").toISOString();
                        record.push(clone);
                    }
                }
            });
        }
    }

    // Low product users: Fewer events and worse retention
    if (profile["products used"] && profile["products used"].length < PRODUCT_THRESHOLD) {
        if (chance.bool({ likelihood: LOW_PRODUCT_EVENT_REDUCTION_LIKELIHOOD })) {
            // Delete events randomly
            record = record.filter((ev, index) => {
                return !(index > 0 && chance.bool({ likelihood: EVENT_DELETION_RATE }));
            });
        }
    }
}
return record;

// Constants - Edit these to customize role assignments
const ENGINEERING_DEPT = "engineering";
const SALES_DEPT = "sales";
const ENGINEERING_ADMIN_LIKELIHOOD = 50;
const SALES_NO_ACCESS_LIKELIHOOD = 50;
const ADMIN_ROLE = "admin";
const NO_ACCESS_ROLE = "no access";

if (type === "scd-pre") {
    const { type: scdType, profile, scd } = meta;
    const prop = Object.keys(scd)[0];

    // Only apply to user SCDs for role property
    if (scdType === "user" && prop === "role") {
        // Engineering users are admins more often
        if (profile.department === ENGINEERING_DEPT) {
            for (const entry of record) {
                if (chance.bool({ likelihood: ENGINEERING_ADMIN_LIKELIHOOD })) {
                    entry.role = ADMIN_ROLE;
                }
            }
        }

        // Sales users have no access more often
        if (profile.department === SALES_DEPT) {
            for (const entry of record) {
