// Constants - Edit these to customize NPS improvement
const FEATURE_THRESHOLD = 3;
const MONTHLY_NPS_IMPROVEMENT = 0.10; // 10% improvement
const MAX_NPS_SCORE = 10;

if (type === "scd-pre") {
    const { type: scdType, profile, scd } = meta;
    const prop = Object.keys(scd)[0];

    // Only apply to user NPS property
    if (scdType === "user" && prop === "NPS") {
        // Check if user has enough preferred features
        const hasEnoughFeatures = profile["preferred features"] &&
            profile["preferred features"].length >= FEATURE_THRESHOLD;

        if (hasEnoughFeatures) {
            // Apply progressive improvement over time
            let lastNPS = record[0].NPS;

            for (const [index, entry] of record.entries()) {
                if (index === 0) continue; // Skip first entry

                // Increase NPS by improvement factor
                entry.NPS = Math.floor(lastNPS + (lastNPS * MONTHLY_NPS_IMPROVEMENT));

                // Cap at max score
                if (entry.NPS > MAX_NPS_SCORE) entry.NPS = MAX_NPS_SCORE;

                lastNPS = entry.NPS;
            }
        }
    }
}
return record;

// Constants - Edit these to customize MRR trends
const PRODUCT_THRESHOLD = 3;
const MONTHLY_GROWTH_RATE = 0.10; // 10% growth
const CHURN_LIKELIHOOD = 20;

if (type === "scd-pre") {
    const { type: scdType, profile, scd } = meta;
    const prop = Object.keys(scd)[0];

    // Only apply to group MRR property
    if (scdType !== "user" && prop === "MRR") {
        // Multi-product companies grow MRR
        if (profile.products && profile.products.length > PRODUCT_THRESHOLD) {
            let lastMRR = record[0].MRR;

            for (const [index, entry] of record.entries()) {
                if (index === 0) continue; // Skip first entry

                // Apply monthly growth
                entry.MRR = Math.floor(lastMRR * (1 + MONTHLY_GROWTH_RATE));
                lastMRR = entry.MRR;
            }
        }

        // Some companies churn
        if (chance.bool({ likelihood: CHURN_LIKELIHOOD })) {
            const size = record.length;
            const churnIndex = u.integer(1, size - 1);

            // Set MRR to 0 after churn point
            for (const [index, entry] of record.entries()) {
                if (index > churnIndex) {
                    entry.MRR = 0;
                }
            }
        }
    }
}
return record;

// Constants - Edit these to customize CSM impact
const HIGH_PERFORMING_CSM = "AK";
const MRR_BOOST_FACTOR = 1.5; // 50% higher

if (type === "scd-pre") {
    const { type: scdType, profile, scd } = meta;
    const prop = Object.keys(scd)[0];

    // Only apply to group MRR property
    if (scdType !== "user" && prop === "MRR") {
        // Check if account is managed by high-performing CSM
        if (profile.CSM === HIGH_PERFORMING_CSM) {
            for (const entry of record) {
