return record;

// This hook ensures experiment events are always first
const EXPERIMENT_EVENT_NAME = "$experiment_started";

if (type === "funnel-pre") {
    const sequence = u.clone(record.sequence);

    // Check if experiment event exists in sequence
    if (sequence.includes(EXPERIMENT_EVENT_NAME)) {
        // Remove from current position
        const newSequence = sequence.filter((event) => event !== EXPERIMENT_EVENT_NAME);

        // Add to beginning
        newSequence.unshift(EXPERIMENT_EVENT_NAME);

        record.sequence = newSequence;
    }
}
return record;

// Constants - Edit these to customize conversion trends
const DAYS_AGO_IMPROVEMENT = 30;
const BEFORE_MIN_FACTOR = 0.5; // 50% of normal
const BEFORE_MAX_FACTOR = 0.9; // 90% of normal
const IMPROVEMENT_DAYS = 30;
const MAX_IMPROVEMENT_FACTOR = 2.0; // 200% of normal

if (type === "funnel-pre") {
    const NOW = dayjs();
    const IMPROVEMENT_DATE = NOW.subtract(DAYS_AGO_IMPROVEMENT, 'day');
    const parsedFirstEventTime = dayjs.unix(meta.firstEventTime);

    // Adjust for time offset
    const actualFunnelTime = parsedFirstEventTime.add(
        NOW.diff(dayjs.unix(global.FIXED_NOW), 'h'),
        'h'
    );

    // Before improvement: Worse conversion
    if (actualFunnelTime.isBefore(IMPROVEMENT_DATE)) {
        record.conversionRate *= decimal(BEFORE_MIN_FACTOR, BEFORE_MAX_FACTOR, 3);
    }

    // After improvement: Progressive improvement
    if (actualFunnelTime.isAfter(IMPROVEMENT_DATE)) {
        // Calculate days since improvement (capped at improvement period)
        const daysSinceImprovement = Math.min(
            IMPROVEMENT_DAYS,
            actualFunnelTime.diff(IMPROVEMENT_DATE, 'day')
        );

        // Calculate improvement factor (0 to 100% over period)
        const improvementPercent = daysSinceImprovement / IMPROVEMENT_DAYS;
        const improvementFactor = 1.0 + (improvementPercent * (MAX_IMPROVEMENT_FACTOR - 1.0));

        record.conversionRate *= decimal(1.0, MAX_IMPROVEMENT_FACTOR, 4) * improvementFactor;
    }
}
return record;

// Constants - Edit these to customize power user behavior
const POWER_USER_THRESHOLD = 10; // events per week
const POWER_USER_PROPERTY_MULTIPLIER = 2.0;
const POWER_USER_CONVERSION_BOOST = 40; // percentage points
const REGULAR_USER_ERROR_RATE = 5; // percentage

// Track power users across hook types
let isPowerUser = false;

// STEP 1: Identify power users from their event volume
if (type === "everything") {
    const { profile, distinct_id } = meta;

    // Count events in the last 7 days
    const sevenDaysAgo = dayjs().subtract(7, 'days');
    const recentEvents = record.filter(event => 
        dayjs(event.time).isAfter(sevenDaysAgo)
    );

    // Mark as power user if above threshold
    if (recentEvents.length > POWER_USER_THRESHOLD) {
        isPowerUser = true;

        // Remove all error events from power users
        record = record.filter(event => 
            event.event !== "error" && 
            event.event !== "timeout" &&
            event.event !== "crash"
        );
    } else {
        // Regular users occasionally have errors
        if (chance.bool({ likelihood: REGULAR_USER_ERROR_RATE })) {
            const errorEvent = {
                event: "error",
                time: chance.pickone(record).time,
                error_type: "timeout",
                distinct_id: distinct_id
            };
            record.push(errorEvent);
        }
    }
}

// STEP 2: Boost numeric properties for power users
if (type === "event" && isPowerUser) {
    // Double all numeric properties for power users
    Object.keys(record).forEach(key => {
        if (typeof record[key] === 'number' && key !== 'time') {
            record[key] = Math.round(record[key] * POWER_USER_PROPERTY_MULTIPLIER);
        }
    });
}

// STEP 3: Improve funnel conversion for power users
if (type === "funnel-pre" && isPowerUser) {
    // Increase conversion rate
    if (record.conversionRate) {
        const currentRate = record.conversionRate * 100;
        const boostedRate = Math.min(95, currentRate + POWER_USER_CONVERSION_BOOST);
        record.conversionRate = boostedRate / 100;
    }

    // Reduce time between funnel steps
    if (record.timing === "random") {
        record.timing = "tight"; // Faster progression
    }
}

return record;
